    setTouchCurrent(e.targetTouches[0].clientX);
  }

  const onTouchEnd = () => {
    setIsDragging(false);
    const diff = touchStart - touchCurrent;
    const threshold = 50; 

    if (Math.abs(diff) > threshold) {
        if (diff > 0) {
           setActiveSlide(prev => (prev + 1) % slides.length);
        } else {
           setActiveSlide(prev => (prev - 1 + slides.length) % slides.length);
