                        <p className="text-slate-500 dark:text-slate-400 text-xs mb-4">Full Syllabus • 3 Hours</p>
                        <button className="bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-950 px-4 py-2 rounded-xl text-xs font-bold shadow-md">Register Now</button>
                    </div>
                </div>
            </div>
        </div>
    );
};

// Practice Screen
const PracticeScreen = ({ onSelectChapter, navigate, profile }: { onSelectChapter: (subject: string, chapter: string) => void, navigate: any, profile: Profile | null }) => {
    const [subjects, setSubjects] = useState<string[]>([]);
    const [searchParams, setSearchParams] = useSearchParams();
    const selectedSubject = searchParams.get('subject');

    const [chapters, setChapters] = useState<{en: string, hi: string, count: number}[]>([]);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
      api.getSubjects().then(setSubjects);
    }, []);

    useEffect(() => {
      if (selectedSubject) {
          setLoading(true);
          api.getChapterStats(selectedSubject).then(data => {
              setChapters(data);
              setLoading(false);
          });
      }
    }, [selectedSubject]);

    const handleAppBack = () => {
        if (selectedSubject) {
            setSearchParams({}, { replace: true }); 
            return true; 
        } else {
            navigate('/'); 
            return true; 
        }
    };

    useBackHandler(handleAppBack, true); 

    return (
        <div className="h-full flex flex-col bg-white dark:bg-slate-950 transition-colors duration-300">
            <div className="sticky top-0 z-50 px-5 pb-3 pt-safe-header bg-white dark:bg-slate-950 flex justify-between items-center border-b border-slate-100 dark:border-slate-800 shadow-sm">
                <div className="flex items-center gap-3">
                    <button onClick={handleAppBack} className="text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors p-1 -ml-1 rounded-full active:bg-slate-100 dark:active:bg-slate-900">
                        <i className="fa-solid fa-chevron-left text-lg"></i>
                    </button>
                    <h2 className="text-xl font-black text-slate-900 dark:text-white">
                        {selectedSubject || 'Practice'}
                    </h2>
                </div>
                <div className="flex items-center gap-1 text-brand-500 dark:text-brand-400 font-black">
                    <i className="fa-solid fa-bolt text-xs"></i>
                    <span>{profile?.weekly_xp || 0}</span>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto hide-scrollbar p-5 pb-24 animate-fade-in">
                {!selectedSubject ? (
                    <>
                        <h2 className="text-2xl font-black text-slate-900 dark:text-white mb-6">Select <span className="text-brand-500">Subject</span></h2>
                        <div className="grid grid-cols-2 gap-4">
                            {subjects.map(sub => (
                                <div key={sub} onClick={() => setSearchParams({ subject: sub }, { replace: true })} className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center gap-2 cursor-pointer active:scale-95 transition-transform hover:bg-slate-50 dark:hover:bg-slate-800 hover:border-brand-500/50 group">
                                    <SubjectIcon subject={sub} />
                                    <span className="font-bold text-slate-600 dark:text-slate-300 text-sm group-hover:text-slate-900 dark:group-hover:text-white transition-colors">{sub}</span>
                                </div>
                            ))}
                        </div>
                    </>
                ) : (
                    <div className="space-y-3">
                        {loading ? (
                            <div className="text-center p-10 text-slate-500 text-sm font-bold animate-pulse">Loading chapters...</div>
                        ) : (
                            chapters.map((chap, idx) => (
                                <div key={idx} onClick={() => onSelectChapter(selectedSubject, chap.en)} className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm active:scale-[0.98] transition-transform flex items-center justify-between cursor-pointer hover:border-brand-500/30 group">
                                    <div>
                                        <h4 className="font-bold text-slate-700 dark:text-slate-200 text-sm group-hover:text-brand-600 dark:group-hover:text-brand-400 transition-colors">
                                            {idx + 1}. {chap.en}
                                        </h4>
                                        {chap.hi && <p className="text-xs text-slate-500 mt-1 font-medium">{chap.hi}</p>}
                                    </div>
                                    <div className="w-8 h-8 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-slate-500 group-hover:bg-brand-500/20 group-hover:text-brand-600 dark:group-hover:text-brand-400 transition-colors">
                                        <i className="fa-solid fa-chevron-right text-xs"></i>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

// Result Screen
const ResultScreen = ({ stats, onHome }: { stats: any, onHome: () => void }) => {
    if(!stats) return <div className="h-screen flex items-center justify-center bg-white dark:bg-slate-950 text-slate-400">Loading Result...</div>;
    const score = stats.correct * 1; 
    return (
        <div className="h-[100dvh] overflow-y-auto bg-white dark:bg-slate-950 p-6 animate-slide-up pb-20 flex flex-col items-center justify-center text-center transition-colors duration-300">
            <div className="w-20 h-20 bg-brand-500/10 rounded-full flex items-center justify-center mb-6 border border-brand-500/20">
                <i className="fa-solid fa-trophy text-4xl text-brand-500"></i>
            </div>
            <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-2">Test Completed</h2>
            <p className="text-slate-500 dark:text-slate-400 font-medium mb-8">Great job! Here is your performance.</p>

            <div className="bg-slate-50 dark:bg-slate-900 rounded-3xl p-8 w-full mb-8 border border-slate-200 dark:border-slate-800">
                <div className="text-6xl font-black mb-2 text-brand-500 dark:text-brand-400">{score}</div>
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-6">Total Score</div>

                <div className="grid grid-cols-2 gap-4 w-full">
                    <div className="bg-white dark:bg-slate-950 p-4 rounded-2xl border border-slate-200 dark:border-slate-800"><p className="text-2xl font-black text-emerald-500 dark:text-emerald-400">{stats.correct}</p><p className="text-[10px] uppercase font-bold text-slate-500">Correct</p></div>
                    <div className="bg-white dark:bg-slate-950 p-4 rounded-2xl border border-slate-200 dark:border-slate-800"><p className="text-2xl font-black text-rose-500 dark:text-rose-400">{stats.wrong}</p><p className="text-[10px] uppercase font-bold text-slate-500">Wrong</p></div>
                </div>
            </div>

            <button onClick={onHome} className="w-full py-4 bg-brand-600 text-white font-bold rounded-xl shadow-lg hover:scale-[1.02] transition-transform shadow-brand-900/20">Return to Chapters</button>
        </div>
    );
};

export default function App() {
  const [session, setSession] = useState<any>(null);
  const [isAppInitializing, setIsAppInitializing] = useState(true);

  const [userProfile, setUserProfile] = useState<Profile | null>(null);
  const [activeTestQuestions, setActiveTestQuestions] = useState<Question[]>([]);
  const [activeSubject, setActiveSubject] = useState<string>('');
  const [testStats, setTestStats] = useState<any>(null);
  const [comingSoonTitle, setComingSoonTitle] = useState('');

  // Infinity Practice State
  const [isInfinityOpen, setInfinityOpen] = useState(false);
  const [infinityConfig, setInfinityConfig] = useState<{subject: string, chapters: string[]} | null>(null);
  const [infinityInstantOpen, setInfinityInstantOpen] = useState(false);

  // PYQ Modal State
  const [isPYQOpen, setPYQOpen] = useState(false);
  const [pyqInitialTab, setPyqInitialTab] = useState<'objective' | 'subjective'>('objective');
  const [instantOpen, setInstantOpen] = useState(false); 

  // Dashboard & Achievements Modals State
  const [isDashboardOpen, setDashboardOpen] = useState(false);
  const [isAchievementsOpen, setAchievementsOpen] = useState(false);

  // Double Back to Exit State
  const [exitAttempted, setExitAttempted] = useState(false);

  const navigate = useNavigate();
  const location = useLocation();
  const [searchParams, setSearchParams] = useSearchParams();

  useStatusBar();

  useBackHandler(() => {
    if (location.pathname === '/' && !isInfinityOpen && !isPYQOpen && !isDashboardOpen && !isAchievementsOpen) {
        if (exitAttempted) {
            return false; 
        } else {
            setExitAttempted(true);
            setTimeout(() => setExitAttempted(false), 2000); 
            return true; 
        }
    }
    return false; 
  }, location.pathname === '/' && !isInfinityOpen && !isPYQOpen && !isDashboardOpen && !isAchievementsOpen);

  useEffect(() => {
    let mounted = true;
    const restoreSession = async () => {
      try {
        const { data: { session }, error } = await supabase.auth.getSession();
        if (error) throw error;
        if (mounted && session) {
            setSession(session);
            fetchProfile(session.user.id).catch(console.error);
        }
      } catch (error) {
        console.error("Session fail", error);
      } finally {
        if (mounted) setIsAppInitializing(false);
      }
    };
    restoreSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (!mounted) return;
      setSession(session);
      if (session) fetchProfile(session.user.id).catch(console.error);
      else setUserProfile(null);
      setIsAppInitializing(false);
    });

    return () => { mounted = false; subscription.unsubscribe(); };
  }, []);

  useEffect(() => {
    const mode = searchParams.get('mode');
    setInfinityOpen(mode === 'infinity');
  }, [searchParams]);

  useEffect(() => {
    if (location.state && (location.state as any).returnTo === 'infinity') {
      setInfinityInstantOpen(true);
      if (!searchParams.get('mode')) setSearchParams({ mode: 'infinity' }, { replace: true });
      window.history.replaceState({}, document.title);
    } else {
      setInfinityInstantOpen(false);
    }
  }, [location, searchParams, setSearchParams]);

  useEffect(() => {
    if (location.state && (location.state as any).openPYQ) {
        const state = location.state as any;
        setPyqInitialTab(state.tab || 'objective');
        setInstantOpen(true); 
        setPYQOpen(true);
        window.history.replaceState({}, document.title);
    } else {
        setInstantOpen(false); 
    }
  }, [location]);

  const fetchProfile = async (userId: string) => {
    const data = await api.getProfile(userId);
    if (!data) {
        const { data: { user } } = await supabase.auth.getUser();
        if (user) {
            const fullName = user?.user_metadata?.full_name || 'Student';
            const avatarUrl = user?.user_metadata?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${userId}`;
            const newProfile = await api.createProfile(userId, fullName, avatarUrl);
            if (newProfile) setUserProfile(newProfile);
        }
    } else {
        setUserProfile(data);
    }
  };

  const handleStartTest = async (subject: string, chapterEn: string) => {
    const qs = await api.getQuestionsByChapter(subject, chapterEn);
    if (qs.length > 0) {
      setActiveSubject(subject);
      setActiveTestQuestions(qs);
      navigate('/test');
    } else {
      setComingSoonTitle(`${subject} - ${chapterEn}`);
      navigate('/coming-soon');
    }
  };

  const handleTestComplete = async (stats: any) => {
    setTestStats(stats);
    if (session?.user?.id) {
        const submission: TestSubmission = {
            userId: session.user.id,
            subject: activeSubject || 'Practice',
            testType: 'Practice',
            totalQuestions: stats.correct + stats.wrong + stats.skipped,
            correct: stats.correct,
            wrong: stats.wrong,
            skipped: stats.skipped,
            timeTaken: stats.totalTime,
            date: new Date().toISOString()
        };
        await api.submitTestResult(submission);
        await fetchProfile(session.user.id); 
    }
    navigate('/results', { replace: true });
  };

  const handleInfinitySubjectUpdate = (sub: string | null) => {
      const newParams: any = { mode: 'infinity' };
      if (sub) newParams.subject = sub;
      setSearchParams(newParams, { replace: true });
  };

  if (isAppInitializing) return <SplashScreen />;
  if (!session) return <LoginScreen onLoginSuccess={(s) => { setSession(s); navigate('/', { replace: true }); }} />;

  const NavIcon = ({ icon, label, target }: { icon: string, label: string, target: string }) => {
      const isActive = location.pathname === target || (target !== '/' && location.pathname.startsWith(target));
      return (
        <button onClick={() => navigate(target)} className={`flex flex-col items-center justify-center w-16 gap-0.5 transition-all ${isActive ? 'text-brand-500 dark:text-brand-400' : 'text-slate-500 dark:text-slate-500 hover:text-slate-900 dark:hover:text-slate-300'}`}>
            <i className={`fa-solid ${icon} text-lg mb-0.5`}></i>
            <span className="text-[10px] font-bold tracking-wide leading-none">{label}</span>
            <div className={`w-1 h-1 rounded-full mt-0.5 transition-opacity ${isActive ? 'bg-brand-500 dark:bg-brand-400 opacity-100' : 'opacity-0'}`}></div>
        </button>
      )
  };

  const showNav = ['/', '/practice', '/rewards', '/profile', '/exam'].includes(location.pathname);
  const showTopHeader = location.pathname === '/';

  return (
    <div className="max-w-md mx-auto h-[100dvh] flex flex-col bg-white dark:bg-slate-950 font-sans relative shadow-2xl overflow-hidden text-slate-900 dark:text-white transition-colors duration-300">

        {showTopHeader && (
            <div className="px-5 pb-3 pt-safe-header bg-white dark:bg-slate-950 flex justify-between items-center sticky top-0 z-30 border-b border-slate-100 dark:border-slate-800 shadow-sm transition-all">
                <div className="flex items-center gap-2"><RaftaarLogo /></div>
                <div className="flex items-center gap-4">
                    <div className="flex flex-col items-end">
                        <span className="text-[10px] text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider">Weekly XP</span>
                        <div className="flex items-center gap-1 text-brand-500 dark:text-brand-400 font-black">
                             <i className="fa-solid fa-bolt text-xs"></i>
                             <span>{userProfile?.weekly_xp || 0}</span>
                        </div>
                    </div>
                    <div className="w-9 h-9 rounded-full bg-slate-50 dark:bg-slate-900 p-0.5 border border-slate-200 dark:border-slate-700 cursor-pointer shadow-sm" onClick={() => setDashboardOpen(true)}>
                        <img src={userProfile?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${session.user.email}`} className="w-full h-full rounded-full" alt="User" />
                    </div>
                </div>
            </div>
        )}

        <div className="flex-1 overflow-y-auto hide-scrollbar relative z-10">
            <AnimatePresence>
                <Routes location={location} key={location.pathname}>
                    <Route 
                        path="/" 
                        element={
                            <HomeScreen 
                                profile={userProfile} 
                                setComingSoonTitle={(t) => { setComingSoonTitle(t); navigate('/coming-soon'); }} 
                                onOpenInfinity={() => setSearchParams({ mode: 'infinity' }, { replace: true })} 
                                onOpenPYQ={() => { setInstantOpen(false); setPyqInitialTab('objective'); setPYQOpen(true); }}
                                onOpenDashboard={() => setDashboardOpen(true)}
                                onOpenAchievements={() => setAchievementsOpen(true)}
                                navigate={navigate} 
                            />
                        } 
                    />
                    <Route path="/practice" element={<PracticeScreen onSelectChapter={handleStartTest} navigate={navigate} profile={userProfile} />} />
                    <Route path="/exam" element={<ExamScreen showCS={() => { setComingSoonTitle('BSEB Physics Mega Mock'); navigate('/coming-soon'); }} profile={userProfile} navigate={navigate} />} />
                    <Route path="/rewards" element={<RewardsScreen profile={userProfile} session={session} navigate={navigate} />} />

                    <Route 
                        path="/pyq-test" 
                        element={
                            <InfinityTestScreen 
                                userId={session?.user?.id} 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                isPYQ={true} 
                                pyqYear={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => { 
                                    if(session?.user?.id) fetchProfile(session.user.id); 
                                    navigate('/', { replace: true, state: { openPYQ: true, tab: 'objective' } });
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/pyq-learn" 
                        element={
                            <PYQSubjectiveScreen 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                year={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => navigate('/', { replace: true, state: { openPYQ: true, tab: 'subjective' } })}
                                defaultLanguage={userProfile?.exam_language} 
                            />
                        } 
                    />

                    <Route path="/shorts" element={<ShortsScreen profile={userProfile} session={session} navigate={navigate} onInteractionSubmit={async (qId, isCorrect, isLiked, time) => { if (session?.user?.id) { await api.submitShortsInteraction(session.user.id, qId, isCorrect, isLiked, time); fetchProfile(session.user.id); } }} />} />

                    <Route 
                        path="/results" 
                        element={
                            <ResultScreen 
                                stats={testStats} 
                                onHome={() => {
                                    if (activeSubject) {
                                        navigate(`/practice?subject=${activeSubject}`, { replace: true });
                                    } else {
                                        navigate('/', { replace: true, state: { openPYQ: true, tab: 'objective' } });
                                    }
                                }} 
                            />
                        } 
                    />

                    <Route 
                        path="/test" 
                        element={
                            <TestInterface 
                                questions={activeTestQuestions} 
                                subjectName={activeSubject} 
                                userId={session?.user?.id} 
                                onExit={() => {
                                    if (activeSubject) {
                                        navigate(`/practice?subject=${encodeURIComponent(activeSubject)}`, { replace: true });
                                    } else {
                                        navigate('/', { replace: true });
                                    }
                                }} 
                                onComplete={handleTestComplete} 
                                onAnswerSubmit={async (qId, opt, correct, timeTaken) => { await api.submitAnswer(session.user.id, qId, opt, correct, timeTaken); }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/infinity-test" 
                        element={
                            infinityConfig ? 
                            <InfinityTestScreen 
                                userId={session.user.id} 
                                subject={infinityConfig.subject} 
                                selectedChapters={infinityConfig.chapters} 
                                onExit={async () => { 
                                    if(session?.user?.id) await fetchProfile(session.user.id); 
                                    const subjectParam = infinityConfig?.subject ? `&subject=${encodeURIComponent(infinityConfig.subject)}` : '';
                                    navigate(`/?mode=infinity${subjectParam}`, { replace: true, state: { returnTo: 'infinity' } });
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            /> : 
                            <div className="p-10 text-center">Loading...</div>
                        } 
                    />
                    <Route 
                        path="/coming-soon" 
                        element={
                            <FullPageComingSoon 
                                title={comingSoonTitle} 
                                onClose={() => navigate(-1)} 
                                profile={userProfile}
                            />
                        } 
                    />
                </Routes>
            </AnimatePresence>
        </div>

        <InfinityPracticeModal 
            isOpen={isInfinityOpen} 
            onClose={() => setSearchParams({}, { replace: true })} 
            userId={session?.user?.id}
            initialSubject={searchParams.get('subject')}
            onUpdateSubject={handleInfinitySubjectUpdate}
            instantOpen={infinityInstantOpen}
            onStartSession={(subject, chapters) => { 
                setInfinityConfig({ subject, chapters }); 
                navigate('/infinity-test'); 
            }} 
        />

        <PYQDashboard 
            isOpen={isPYQOpen}
            initialTab={pyqInitialTab}
            instantOpen={instantOpen}
            onClose={() => setPYQOpen(false)}
            onSelectYear={async (subject, year, type) => { 
                setPYQOpen(false); 
                if (type === 'objective') { 
                    navigate(`/pyq-test?subject=${subject}&year=${year}`); 
                } else { 
                    navigate(`/pyq-learn?subject=${subject}&year=${year}`); 
                } 
            }} 
        />

        <DashboardModal 
            isOpen={isDashboardOpen} 
            onBack={() => setDashboardOpen(false)} 
            userId={session?.user?.id}
            profile={userProfile}
        />

        <AchievementsModal 
            isOpen={isAchievementsOpen} 
            onBack={() => setAchievementsOpen(false)}
            profile={userProfile}
        />

        <AnimatePresence>
            {exitAttempted && (
                <motion.div 
                    initial={{ y: 50, opacity: 0, scale: 0.9 }}
                    animate={{ y: 0, opacity: 1, scale: 1 }}
                    exit={{ y: 50, opacity: 0, scale: 0.95 }}
                    className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-slate-800 dark:bg-slate-700 text-white px-6 py-3 rounded-full text-sm font-bold shadow-lg z-[60] border border-slate-700 dark:border-slate-600 flex items-center gap-2 pb-safe"
                >
                    <div className="w-2 h-2 bg-brand-400 rounded-full animate-pulse"></div>
                    Press back again to exit
                </motion.div>
            )}
        </AnimatePresence>

        {showNav && (
            <div className="fixed bottom-0 w-full max-w-md bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-800 flex justify-around py-2 pb-safe-offset-2 z-40 shadow-lg">
                <div className="pb-safe flex w-full justify-around pt-2">
                    <NavIcon icon="fa-house" label="Home" target="/" />
                    <NavIcon icon="fa-book-open" label="Practice" target="/practice" />
                    <NavIcon icon="fa-file-signature" label="Exam" target="/exam" />
                    <NavIcon icon="fa-trophy" label="Rewards" target="/rewards" />
                </div>
            </div>
        )}
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Question, Language } from '../types';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Clock } from 'lucide-react';
import { useBackHandler } from '../hooks/useBackHandler';

interface TestInterfaceProps {
  questions: Question[];
  subjectName?: string;
  userId: string;
  onComplete: (stats: { correct: number, wrong: number, skipped: number, totalTime: number }) => void;
  onExit: () => void;
  onAnswerSubmit: (qId: number, option: string, isCorrect: boolean, timeTaken: number) => void;
  defaultLanguage?: 'Hindi' | 'English'; 
}

export const TestInterface: React.FC<TestInterfaceProps> = ({ 
    questions, 
    subjectName, 
    userId, 
    onComplete, 
    onExit, 
    onAnswerSubmit,
    defaultLanguage = 'English'
}) => {
  const [lang, setLang] = useState<Language>(defaultLanguage === 'Hindi' ? 'hi' : 'en');

  useEffect(() => {
      setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  }, [defaultLanguage]);

  const [currentIndex, setCurrentIndex] = useState(0);
  const [grid, setGrid] = useState<Record<number, { status: string, answer: string | null }>>({});
  const [timer, setTimer] = useState(0); 
  const [showSolution, setShowSolution] = useState(false);
  const [stats, setStats] = useState({ correct: 0, wrong: 0, answered: 0 });
  const [questionStartTime, setQuestionStartTime] = useState<number>(Date.now());
  const [submitting, setSubmitting] = useState(false);

  // Exit Modal State
  const [showExitModal, setShowExitModal] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  const handleNavigationBack = () => {
     if (showExitModal) {
         setShowExitModal(false); 
         return true; 
     }
     if (!submitting) {
         setShowExitModal(true); 
         return true;
     }
     return true; 
  };

  useBackHandler(() => {
    return handleNavigationBack();
  }, !submitting); 

  useEffect(() => {
    const initialGrid: any = {};
    questions.forEach((_, i) => {
        initialGrid[i] = { status: 'not-visited', answer: null };
    });
    if(initialGrid[0]) initialGrid[0].status = 'not-answered';
    setGrid(initialGrid);
    setQuestionStartTime(Date.now()); 
  }, [questions]);

  useEffect(() => {
    const t = setInterval(() => setTimer(time => time + 1), 1000);
    return () => clearInterval(t);
  }, []);

  const currentQ = questions[currentIndex];
  if (!currentQ) return <div className="p-10 text-center flex flex-col items-center justify-center h-screen bg-white dark:bg-slate-950 text-slate-900 dark:text-white"><div className="w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div><p className="mt-4 text-slate-500 dark:text-slate-400 font-bold">Loading Test...</p></div>;

  const currentStatus = grid[currentIndex] || { status: 'not-visited', answer: null };

  const handleOptionSelect = (option: string) => {
    if (showSolution) return; 

    const isCorrect = option === currentQ.correct_option;
    const timeTaken = Math.floor((Date.now() - questionStartTime) / 1000); 

    const newGrid = { ...grid };
    newGrid[currentIndex] = {
        answer: option,
        status: isCorrect ? 'answered' : 'not-answered', 
    };
    setGrid(newGrid);
    setShowSolution(true);

    setStats(s => ({
        ...s,
        answered: s.answered + 1,
        correct: isCorrect ? s.correct + 1 : s.correct,
        wrong: !isCorrect ? s.wrong + 1 : s.wrong
    }));

    onAnswerSubmit(currentQ.id, option, isCorrect, timeTaken);
  };

  const finishTest = async () => {
    if (submitting) return;
    setSubmitting(true);

    let correct = 0, wrong = 0, skipped = 0;
    Object.values(grid).forEach((g: any, i) => {
        const q = questions[i];
        if (g.answer) {
            if (g.answer === q.correct_option) correct++;
            else wrong++;
        } else {
            skipped++;
        }
    });

    onComplete({ correct, wrong, skipped, totalTime: timer });
  };

  const handleNext = () => {
    setShowSolution(false);
    if (currentIndex < questions.length - 1) {
      const nextIndex = currentIndex + 1;
      const newGrid = { ...grid };
      if (newGrid[nextIndex].status === 'not-visited') {
          newGrid[nextIndex].status = 'not-answered';
      }
      setGrid(newGrid);
      setCurrentIndex(nextIndex);
      setQuestionStartTime(Date.now());

      if (scrollRef.current) {
          const itemWidth = 40; 
          const containerWidth = scrollRef.current.clientWidth;
          const scrollPos = (nextIndex * itemWidth) - (containerWidth / 2) + (itemWidth / 2);
          scrollRef.current.scrollTo({ left: scrollPos, behavior: 'smooth' });
      }
    } else {
        finishTest();
    }
  };

  const handlePrev = () => {
      setShowSolution(false);
      if (currentIndex > 0) {
        setCurrentIndex(currentIndex - 1);
        setQuestionStartTime(Date.now());
      }
  }

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const getText = (field: string) => {
    const en = currentQ[`${field}_en` as keyof Question] as string;
    const hi = currentQ[`${field}_hi` as keyof Question] as string;
    return lang === 'hi' ? (hi || en) : en;
  };

  const questionsLeft = questions.length - stats.answered;

  return (
    <div className="flex flex-col h-[100dvh] bg-white dark:bg-slate-950 relative font-sans animate-fade-in overflow-hidden transition-colors duration-300">

        {/* --- HEADER --- */}
        <div className="px-4 pb-3 pt-safe-header bg-white dark:bg-slate-950 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center z-50 sticky top-0 shadow-sm shrink-0">
             <div className="flex items-center gap-3">
                 <button onClick={handleNavigationBack} className="text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white p-1 -ml-1 rounded-full active:bg-slate-100 dark:active:bg-slate-900">
                    <ArrowLeft size={20} />
                 </button>

                 <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-900 px-2 py-1 rounded-lg border border-slate-200 dark:border-slate-800">
                    <Clock size={14} className="text-slate-500 dark:text-slate-400" />
                    <span className="font-mono font-bold text-slate-700 dark:text-slate-200 text-sm tracking-wider">{formatTime(timer)}</span>
                 </div>
            </div>

            <div className="text-xs text-slate-500 dark:text-slate-500 font-bold uppercase tracking-wider truncate max-w-[120px]">{subjectName || 'Test'}</div>

            <button 
                onClick={finishTest} 
                disabled={submitting}
                className="bg-red-500/10 text-red-500 dark:text-red-400 px-3 py-1.5 rounded-lg text-[10px] font-bold border border-red-500/20 hover:bg-red-500/20 transition-colors disabled:opacity-50 flex items-center gap-2"
            >
                {submitting && <div className="w-3 h-3 border-2 border-red-500 dark:border-red-400 border-t-transparent rounded-full animate-spin"></div>}
                {submitting ? 'Saving...' : 'Submit'}
            </button>
        </div>

        {/* --- LIVE STATS GRID --- */}
        <div className="bg-white dark:bg-slate-950 border-b border-slate-100 dark:border-slate-800 py-2 px-4 flex justify-between items-center text-[10px] font-bold text-slate-500 shrink-0">
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-green-500"></div> {stats.correct} Correct</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div> {stats.wrong} Wrong</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"></div> {questionsLeft} Left</div>
        </div>

        {/* --- HORIZONTAL PALETTE STRIP --- */}
        <div className="bg-slate-50 dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 py-3 shrink-0">
            <div ref={scrollRef} className="flex overflow-x-auto px-4 gap-2 hide-scrollbar snap-x scroll-smooth">
                {questions.map((_, i) => {
                    const isCorrect = grid[i]?.answer && grid[i]?.answer === questions[i].correct_option;
                    let bg = 'bg-white dark:bg-slate-950 text-slate-500 border-slate-200 dark:border-slate-800';

                    if (grid[i]?.answer) {
                        if (isCorrect) bg = 'bg-green-600 text-white border-green-500';
                        else bg = 'bg-red-600 text-white border-red-500';
                    } else if (i === currentIndex) {
                        bg = 'ring-1 ring-brand-500 border-brand-500 text-brand-500 dark:text-brand-400 bg-brand-50 dark:bg-brand-900/20';
                    }

                    return (
                        <div key={i} onClick={() => { 
                            setCurrentIndex(i); 
                            setShowSolution(!!grid[i]?.answer);
                            setQuestionStartTime(Date.now());
                        }} className={`snap-center shrink-0 w-9 h-9 rounded-lg flex items-center justify-center text-xs font-bold border transition-all cursor-pointer relative ${bg}`}>
                            {i + 1}
                        </div>
                    )
                })}
            </div>
        </div>

        {/* --- QUESTION AREA --- */}
        <div className="flex-1 overflow-y-auto p-5 pb-32 hide-scrollbar w-full">
            <div className="flex justify-between items-start mb-4">
                 <span className="font-bold text-slate-500 text-[10px] uppercase tracking-wider bg-slate-100 dark:bg-slate-900 px-2 py-1 rounded border border-slate-200 dark:border-slate-800">Question {currentIndex + 1}</span>
                 <button onClick={() => setLang(l => l==='en'?'hi':'en')} className="flex items-center gap-1 bg-slate-100 dark:bg-slate-900 px-3 py-1 rounded-full border border-slate-200 dark:border-slate-800 text-[10px] font-bold text-slate-500 dark:text-slate-400 active:scale-95 transition-transform shadow-sm">
                    <i className="fa-solid fa-language"></i> {lang === 'en' ? 'ENG' : 'HIN'}
                </button>
            </div>

            <p className="text-lg font-bold text-slate-900 dark:text-white leading-relaxed mb-4 font-serif break-words">
                {getText('question_text')}
            </p>

            <div className="flex items-center gap-2 mb-6">
                <span className="bg-green-500/10 text-green-500 dark:text-green-400 text-[10px] font-bold px-2 py-1 rounded border border-green-500/20">
                    +1.0
                </span>
                <span className="bg-red-500/10 text-red-500 dark:text-red-400 text-[10px] font-bold px-2 py-1 rounded border border-red-500/20">
                    -0.0
                </span>
            </div>

            <div className="space-y-4">
                {['A','B','C','D'].map((opt) => {
                    const optText = getText(`option_${opt.toLowerCase()}`);
                    const isSelected = currentStatus.answer === opt;
                    const isCorrect = opt === currentQ.correct_option;

                    let cardClass = "p-4 rounded-xl border-2 cursor-pointer flex items-start gap-4 transition-all active:scale-[0.98] ";
                    let circleClass = "w-7 h-7 rounded-full border-2 flex items-center justify-center text-sm font-bold shrink-0 transition-colors mt-0.5 ";

                    if (showSolution) {
                        if(isCorrect) {
                            cardClass += "border-green-500 bg-green-50 dark:bg-green-950/30";
                            circleClass += "bg-green-500 text-white border-green-500";
                        } else if (isSelected && !isCorrect) {
                            cardClass += "border-red-500 bg-red-50 dark:bg-red-950/30";
                            circleClass += "bg-red-500 text-white border-red-500";
                        } else {
                            cardClass += "border-slate-200 dark:border-slate-800 opacity-50";
                            circleClass += "border-slate-300 dark:border-slate-700 text-slate-500";
                        }
                    } else {
                        cardClass += "border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 hover:border-brand-500/50";
                        circleClass += "border-slate-300 dark:border-slate-700 text-slate-400 dark:text-slate-400 bg-slate-50 dark:bg-slate-950";
                    }

                    return (
                        <div key={opt} onClick={() => handleOptionSelect(opt)} className={cardClass}>
                            <div className={circleClass}>{opt}</div>
                            <div className="flex-1 text-sm font-medium text-slate-700 dark:text-slate-200 break-words leading-relaxed">
                                {optText}
                            </div>
                        </div>
                    )
                })}
            </div>

            {showSolution && (
                <div className="mt-6 p-5 rounded-xl bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 animate-slide-up">
                    <div className="flex items-center gap-2 mb-2">
                        <i className="fa-solid fa-lightbulb text-blue-500 dark:text-blue-400"></i>
                        <p className="text-xs font-bold text-blue-500 dark:text-blue-400 uppercase">Explanation</p>
                    </div>
                    <p className="text-sm text-slate-700 dark:text-slate-300 leading-relaxed break-words">{getText('solution_short') || "No detailed explanation available for this question."}</p>
                </div>
            )}
        </div>

        {/* --- BOTTOM BAR --- */}
        <div className="absolute bottom-0 w-full bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-800 p-4 pb-safe shadow-[0_-5px_20px_rgba(0,0,0,0.05)] dark:shadow-[0_-5px_20px_rgba(0,0,0,0.2)] z-30 flex items-center gap-4">
            <div className="w-full flex gap-4 pb-2">
                <button onClick={handlePrev} disabled={currentIndex === 0} className="w-1/3 py-3.5 rounded-xl font-bold text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 disabled:opacity-50 hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors">
                    Previous
                </button>

                <button onClick={handleNext} className="flex-1 bg-brand-600 text-white font-bold py-3.5 rounded-xl shadow-lg shadow-brand-500/30 dark:shadow-brand-900 hover:bg-brand-500 transition-colors flex items-center justify-center gap-2 active:scale-[0.98]">
                    {currentIndex === questions.length - 1 ? 'Finish' : 'Save & Next'}
                </button>
            </div>
        </div>

        {/* --- EXIT MODAL --- */}
        <AnimatePresence>
          {showExitModal && (
              <>
                <motion.div 
                    initial={{ opacity: 0 }} animate={{ opacity: 0.5 }} exit={{ opacity: 0 }}
                    onClick={() => setShowExitModal(false)}
                    className="fixed inset-0 bg-black z-40"
                />
                <motion.div
                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 25, stiffness: 300 }}
                    className="fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 rounded-t-[2rem] z-50 p-6 pb-safe shadow-2xl border-t border-slate-100 dark:border-slate-800"
                >
                    <div className="w-12 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full mx-auto mb-6 mt-2"></div>

                    <div className="flex flex-col items-center text-center mb-8">
                        <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mb-4">
                            <i className="fa-solid fa-arrow-right-from-bracket text-2xl text-red-500"></i>
                        </div>
                        <p className="text-slate-900 dark:text-white font-bold text-lg">Exit Test?</p>
                        <p className="text-slate-500 dark:text-slate-400 text-sm mt-1 max-w-xs leading-relaxed">
                            Your current progress will be lost if you exit without submitting.
                        </p>
                    </div>

                    <div className="flex gap-4 pb-4">
                        <button 
                            onClick={onExit} 
                            className="flex-1 py-3.5 rounded-xl border border-slate-200 dark:border-slate-700 text-slate-500 dark:text-slate-300 font-bold hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
                        >
                            Exit
                        </button>
                        <button 
                            onClick={() => setShowExitModal(false)} 
                            className="flex-1 py-3.5 rounded-xl bg-brand-600 text-white font-bold shadow-lg shadow-brand-500/30 dark:shadow-brand-900 hover:bg-brand-500 transition-colors"
                        >
                            Continue
                        </button>
                    </div>
                </motion.div>
              </>
          )}
      </AnimatePresence>
    </div>
  );
};

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --sat: env(safe-area-inset-top);
  --sab: env(safe-area-inset-bottom);
  --sal: env(safe-area-inset-left);
  --sar: env(safe-area-inset-right);
}

html, body, #root {
  height: 100%;
  width: 100%;
  margin: 0;
  padding: 0;
  background-color: #f8faff;
  /* Use dynamic viewport height for mobile browsers */
  min-height: 100dvh;
}

/* Safe Area Utilities */
.pt-safe {
  padding-top: var(--sat);
}
.pb-safe {
  padding-bottom: var(--sab);
}
.mt-safe {
  margin-top: var(--sat);
}
.mb-safe {
  margin-bottom: var(--sab);
}

/* 
   YouTube-Style Header Spacing 
   Ensures at least 24px (approx status bar height) of padding,
   preventing content from being hidden behind the notch 
   even if the browser reports 0px safe area.
*/
.pt-safe-header {
  padding-top: max(env(safe-area-inset-top), 24px);
}

/* Header offset: Standard header height + Safe Area 
   Removed the large offset versions to force use of tighter padding 
   in components directly.
*/
.pt-safe-offset-2 {
  padding-top: calc(var(--sat) + 0.5rem);
}

/* Ensure fade-in animations work */
.animate-fade-in {
  animation: fadeIn 0.5s ease-out;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

import { supabase } from './supabase';
import { Question, Profile, PYQQuestion, DashboardStats, TestHistoryItem, TestSubmission } from '../types';
import { updateUserXP } from './xpService'; 

const FALLBACK_SUBJECTS = ['Physics', 'Chemistry', 'Maths', 'Biology', 'Hindi', 'English'];
const FALLBACK_QUESTIONS: Question[] = [
  {
    id: 101, subject: 'Physics', chapter_name_en: 'Electric Charges and Fields', chapter_name_hi: 'वैद्युत आवेश तथा क्षेत्र', question_text_en: 'The SI unit of electric flux is:', question_text_hi: 'विद्युत फ्लक्स का SI मात्रक है:', option_a_en: 'Weber', option_a_hi: 'वेबर', option_b_en: 'Nm²C⁻¹', option_b_hi: 'Nm²C⁻¹', option_c_en: 'Newton', option_c_hi: 'न्यूटन', option_d_en: 'Volt', option_d_hi: 'वोल्ट', correct_option: 'B', solution_short_en: 'Electric flux Φ = E.dA = (N/C) * m² = Nm²C⁻¹.', solution_short_hi: 'विद्युत फ्लक्स Φ = E.dA = (N/C) * m² = Nm²C⁻¹.', exam_year: '2021A'
  }
];

export const api = {
  // --- AUTHENTICATION ---

  registerOrLogin: async (data: { fullName: string; mobileNumber: string; location: string; examLanguage: 'Hindi' | 'English' }) => {
    try {
        const email = `${data.mobileNumber}@raftaar.local`; 
        const password = `${data.mobileNumber}raftaar2026`; 

        // Try Signing In
        const { data: signInData, error: signInError } = await supabase.auth.signInWithPassword({
            email,
            password
        });

        if (signInData.user) {
            // Update existing profile
            await supabase.from('profiles').update({
                full_name: data.fullName,
                location: data.location,
                mobile_number: data.mobileNumber,
                exam_language: data.examLanguage,
                last_active_at: new Date().toISOString()
            }).eq('id', signInData.user.id);

            return { user: signInData.user, session: signInData.session, error: null };
        }

        // Create New User
        const { data: signUpData, error: signUpError } = await supabase.auth.signUp({
            email,
            password,
            options: { data: { full_name: data.fullName } }
        });

        if (signUpError) throw signUpError;
        if (!signUpData.user) throw new Error("User creation failed");

        // Insert Profile - Default to Bronze and Level 1
        const profileData = {
            id: signUpData.user.id,
            full_name: data.fullName,
            mobile_number: data.mobileNumber,
            location: data.location,
            exam_language: data.examLanguage,
            avatar_url: `https://api.dicebear.com/7.x/avataaars/svg?seed=${data.fullName}`,
            study_minutes: 0,
            total_xp: 0,
            weekly_xp: 0,
            current_level: 1, // Start at Level 1
            current_badge: 'Bronze', // Start as Bronze
            last_active_at: new Date().toISOString(),
        };

        const { error: profileError } = await supabase.from('profiles').upsert(profileData);
        if (profileError) throw profileError;

        return { user: signUpData.user, session: signUpData.session, error: null };

    } catch (error: any) {
        return { user: null, session: null, error: error };
    }
  },

  getProfile: async (userId: string): Promise<Profile | null> => {
    try {
      const { data, error } = await supabase
        .from('leaderboard_view')
        .select('*')
        .eq('id', userId)
        .single();

      if (!error && data) return data;

      const { data: basicData, error: basicError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (basicError) return null;
      return { ...basicData, global_rank: 0 }; 
    } catch (e) { return null; }
  },

  createProfile: async (userId: string, fullName: string, avatarUrl: string): Promise<Profile | null> => {
    try {
        const newProfile = {
            id: userId,
            full_name: fullName,
            avatar_url: avatarUrl,
            study_minutes: 0,
            total_xp: 0,
            weekly_xp: 0,
            current_level: 1,
            current_badge: 'Bronze',
            last_active_at: new Date().toISOString(),
        };

        const { data, error } = await supabase
            .from('profiles')
            .upsert(newProfile, { onConflict: 'id' })
            .select()
            .single();

        if (error) return null;
        return data;
    } catch (e) { return null; }
  },

  getSubjects: async (): Promise<string[]> => {
    try {
      const { data, error } = await supabase.from('questions').select('subject');
      if (error || !data || data.length === 0) return FALLBACK_SUBJECTS;
      const subjects: string[] = Array.from(new Set((data as any[]).map((d: any) => String(d.subject))));
      return subjects.length > 0 ? subjects : FALLBACK_SUBJECTS;
    } catch (e) { return FALLBACK_SUBJECTS; }
  },

  getChapters: async (subject: string): Promise<{en: string, hi: string}[]> => {
    try {
      const { data, error } = await supabase
        .from('questions')
        .select('chapter_name_en, chapter_name_hi')
        .eq('subject', subject)
        .order('id', { ascending: true }); // Ensure DB order
      if (error || !data) return [];
      const uniqueMap = new Map();
      data.forEach((item: any) => {
        if (!uniqueMap.has(item.chapter_name_en)) uniqueMap.set(item.chapter_name_en, { en: item.chapter_name_en, hi: item.chapter_name_hi });
      });
      return Array.from(uniqueMap.values());
    } catch (e) { return []; }
  },

  getQuestionsByChapter: async (subject: string, chapterEn: string): Promise<Question[]> => {
    try {
      const { data } = await supabase.from('questions').select('*').eq('subject', subject).eq('chapter_name_en', chapterEn);
      return data && data.length > 0 ? data : FALLBACK_QUESTIONS.filter(q => q.subject === subject);
    } catch (e) { return []; }
  },

  getRandomQuestion: async (): Promise<Question | null> => {
    try {
       const { data } = await supabase.from('questions').select('*').limit(20); 
       if(!data || data.length === 0) return FALLBACK_QUESTIONS[0];
       return data[Math.floor(Math.random() * data.length)];
    } catch(e) { return FALLBACK_QUESTIONS[0]; }
  },

  submitAnswer: async (userId: string, questionId: number, selectedOption: string, isCorrect: boolean, timeTaken: number) => {
    if (userId === 'demo-user') return true; 

    const { error } = await supabase.from('user_interactions').insert({
        user_id: userId, question_id: questionId, is_correct: isCorrect, time_spent_seconds: timeTaken
    });

    if (!error && isCorrect) {
        await updateUserXP(userId, 1);
    }
    return true;
  },

  submitTestResult: async (data: TestSubmission) => {
    if (data.userId === 'demo-user') return { success: true };
    try {
        const { error } = await supabase.from('user_test_sessions').insert({
            user_id: data.userId, test_type: data.testType, subject: data.subject, total_questions: data.totalQuestions,
            correct_count: data.correct, wrong_count: data.wrong, skipped_count: data.skipped, time_taken_seconds: data.timeTaken, created_at: data.date
        });
        return { success: !error, error };
    } catch (e) { return { success: false }; }
  },

  submitShortsInteraction: async (userId: string, questionId: number, isCorrect: boolean, isLiked: boolean, timeSpentSeconds: number) => {
    if (userId === 'demo-user') return true;

    const { error } = await supabase.from('user_interactions').insert({
        user_id: userId, question_id: questionId, is_correct: isCorrect, is_liked: isLiked, time_spent_seconds: timeSpentSeconds
    });

    if (!error && isCorrect) {
        await updateUserXP(userId, 1);
    }
    return !error;
  },

  getLeaderboard: async (): Promise<Profile[]> => {
      try {
          const { data, error } = await supabase
            .from('leaderboard_view')
            .select('*')
            .order('total_xp', { ascending: false })
            .limit(50);

          if (error) throw error;
          return data as Profile[];
      } catch (e) { return []; }
  },

  getDashboardData: async (userId: string): Promise<DashboardStats> => {
    if (userId === 'demo-user') return { totalQuestions: 0, totalCorrect: 0, totalWrong: 0, accuracy: 0, dailyAttempts: 0, dailyCorrect: 0, dailyWrong: 0, dailyAvgTime: 0, totalTests: 0, history: [], graphData: [] };

    try {
        const { data: sessions } = await supabase.from('user_test_sessions').select('*').eq('user_id', userId).order('created_at', { ascending: false });
        if (!sessions) return { totalQuestions: 0, totalCorrect: 0, totalWrong: 0, accuracy: 0, dailyAttempts: 0, dailyCorrect: 0, dailyWrong: 0, dailyAvgTime: 0, totalTests: 0, history: [], graphData: [] };

        let totalQuestions = 0, totalCorrect = 0, totalWrong = 0;
        sessions.forEach(s => { totalQuestions += (s.total_questions || 0); totalCorrect += (s.correct_count || 0); totalWrong += (s.wrong_count || 0); });
        const accuracy = totalQuestions > 0 ? Math.round((totalCorrect / totalQuestions) * 100) : 0;

        const todayStr = new Date().toISOString().split('T')[0];
        const todaySessions = sessions.filter(s => s.created_at?.startsWith(todayStr));
        let dailyAttempts = 0, dailyCorrect = 0, dailyWrong = 0, dailyTimeTotal = 0;

        todaySessions.forEach(s => { dailyAttempts += (s.total_questions || 0); dailyCorrect += (s.correct_count || 0); dailyWrong += (s.wrong_count || 0); dailyTimeTotal += (s.time_taken_seconds || 0); });
        const dailyAvgTime = dailyAttempts > 0 ? Math.round(dailyTimeTotal / dailyAttempts) : 0;

        const history: TestHistoryItem[] = sessions.slice(0, 20).map((s: any) => ({
            id: s.id, subject: s.subject || 'General', correct: s.correct_count, totalQuestions: s.total_questions, timeTaken: s.time_taken_seconds, date: s.created_at, type: s.test_type
        }));

        const graphMap = new Map<string, number>();
        [...Array(7)].map((_, i) => { const d = new Date(); d.setDate(d.getDate() - i); return d.toISOString().split('T')[0]; }).reverse().forEach(d => graphMap.set(d.slice(5), 0));

        sessions.forEach(s => {
            const dateKey = s.created_at.slice(5, 10);
            if (graphMap.has(dateKey)) graphMap.set(dateKey, (graphMap.get(dateKey) || 0) + (s.correct_count || 0));
        });

        return { totalQuestions, totalCorrect, totalWrong, accuracy, dailyAttempts, dailyCorrect, dailyWrong, dailyAvgTime, totalTests: sessions.length, history, graphData: Array.from(graphMap.entries()).map(([day, score]) => ({ day, score })) };
    } catch (e) { return { totalQuestions: 0, totalCorrect: 0, totalWrong: 0, accuracy: 0, dailyAttempts: 0, dailyCorrect: 0, dailyWrong: 0, dailyAvgTime: 0, totalTests: 0, history: [], graphData: [] }; }
  },

  getChapterStats: async (subject: string): Promise<{ en: string, hi: string, count: number }[]> => {
      try {
          // Ordered by ID to ensure sequence matches database entry order (e.g. Ch1, Ch2)
          const { data } = await supabase
            .from('questions')
            .select('chapter_name_en, chapter_name_hi')
            .eq('subject', subject)
            .order('id', { ascending: true });

          if (!data) return [];
          const map = new Map<string, { en: string, hi: string, count: number }>();
          data.forEach((q: any) => {
              const en = q.chapter_name_en;
              const hi = q.chapter_name_hi || '';
              if (!map.has(en)) map.set(en, { en, hi, count: 0 });
              map.get(en)!.count++;
          });
          return Array.from(map.values());
      } catch (e) { return []; }
  },

  createPracticeSession: async (userId: string, subject: string, chapters: string[]) => 'session-' + Date.now(),

  fetchInfinityBatch: async (chapters: string[], seenIds: number[], qty: number): Promise<Question[]> => {
    if (!chapters.length) return [];
    try {
        const promises = chapters.map(async (chapterName) => {
            let query = supabase.from('questions').select('*').eq('chapter_name_en', chapterName);
            if (seenIds.length > 0) query = query.not('id', 'in', `(${seenIds.join(',')})`);
            const { data } = await query.limit(qty);
            return data as Question[] || [];
        });
        const results = await Promise.all(promises);
        const all = results.flat();
        for (let i = all.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [all[i], all[j]] = [all[j], all[i]]; }
        return all;
    } catch (e) { return []; }
  },

  getPYQs: async (subject: string, year: number, type: string): Promise<PYQQuestion[]> => {
    const { data } = await supabase.from('pyq_questions').select('*').eq('subject', subject).eq('exam_year', year).eq('question_type', type);
    return data as PYQQuestion[] || [];
  }
};

